/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode() : val(0), left(nullptr), right(nullptr) {}
 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:
    int goodNodes(TreeNode* root) {

        int i = goodnode(root, root->val);
        return (i) ? i : i+1;
    }
private:
    int goodnode(TreeNode* root, int max, int value = 0){
        if(root->left){
            if(root->val >= max){
                value++;
                value += goodnode(root->left, root->val);
            }
            else{
                value += goodnode(root->left, max);
            }
        }
        if(root->right){
            if(root->val >= max){
                value++;
                value += goodnode(root->right, root->val);
            }
            else{
                value += goodnode(root->right, max);
            }
        }
        return value;


    }
};

/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode() : val(0), left(nullptr), right(nullptr) {}
 *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
 *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
 * };
 */
class Solution {
public:
    int goodNodes(TreeNode* root) {
        return goodnode(root, root->val);
    }

private:
    int goodnode(TreeNode* root, int max){
        if(root == nullptr) return 0;
        int value = 0;
        if(root->val >= max){
            value++;
            max = root->val;
        }
        value += goodnode(root->left, max);
        value += goodnode(root->right, max);

        return value;
    }
};
